function onLoad() {

	var table = 'x_153465_discovert_route_task_instance';
	g_form.addInfoMessage("<a href='../discovertaskerportal?id=discovertasker_taskdetails&table="+ table +"&sys_id=" + g_form.getUniqueValue() + "&view=sp&target='_blank'>View this task in Portal page</a>");

	// STRY0107400
	if(g_form.getValue('state') == -6 && g_form.getValue('parent') + '' != ''){
		g_form.addInfoMessage(getMessage('Tasker - Draft task(s) can only be published from the top task.'));
	}

}
